function StatsBarChart() {
  return (
    <div className="w-full h-80">
      <ResponsiveBar
        data={[
          { metric: 'Time Saved', before: 100, after: 35 },
          { metric: 'No-Shows', before: 80, after: 20 },
          { metric: 'Booking Time', before: 90, after: 10 },
          { metric: 'Satisfaction', before: 55, after: 95 },
        ]}
        keys={['before', 'after']}
        indexBy="metric"
        margin={{ top: 30, right: 40, bottom: 50, left: 50 }}
        padding={0.3}
        valueScale={{ type: 'linear' }}
        indexScale={{ type: 'band', round: true }}
        colors={['#e2e8f0', '#7c3aed']}
        borderWidth={0}
        borderRadius={4}
        enableLabel={false}
        axisTop={null}
        axisRight={null}
        axisBottom={{
          tickSize: 0,
          tickPadding: 10,
          tickRotation: 0,
        }}
        axisLeft={{
          tickSize: 0,
          tickPadding: 8,
          tickRotation: 0,
          legend: 'Score',
          legendOffset: -40,
        }}
        enableGridY={true}
        gridYValues={[0, 25, 50, 75, 100]}
        theme={{
          grid: {
            line: {
              stroke: '#f1f5f9',
              strokeWidth: 1,
            },
          },
          axis: {
            ticks: {
              text: {
                fontSize: 12,
                fill: '#64748b',
              },
            },
          },
        }}
      />
    </div>
  );
}

